{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.11.11","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"},"kaggle":{"accelerator":"nvidiaTeslaT4","dataSources":[{"sourceType":"datasetVersion","sourceId":2542390,"datasetId":1541666,"databundleVersionId":2585349}],"dockerImageVersionId":31041,"isInternetEnabled":true,"language":"python","sourceType":"script","isGpuEnabled":true}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:32:12.544522Z\",\"iopub.execute_input\":\"2026-04-03T07:32:12.545164Z\",\"iopub.status.idle\":\"2026-04-03T07:33:35.204143Z\",\"shell.execute_reply.started\":\"2026-04-03T07:32:12.545142Z\",\"shell.execute_reply\":\"2026-04-03T07:33:35.203235Z\"}}\nprint(\"Starting Installation...\")\n!pip install -q monai torchio\nprint(\"Installation(s) Complete\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:33:35.206001Z\",\"iopub.execute_input\":\"2026-04-03T07:33:35.206225Z\",\"iopub.status.idle\":\"2026-04-03T07:34:10.467289Z\",\"shell.execute_reply.started\":\"2026-04-03T07:33:35.206205Z\",\"shell.execute_reply\":\"2026-04-03T07:34:10.466716Z\"}}\nimport os\nimport shutil\nimport tarfile\nimport torch\nimport matplotlib.pyplot as plt\nfrom tqdm import tqdm\nimport numpy as np\n\nfrom monai.transforms import (\n    Compose, LoadImaged, EnsureChannelFirstd, Spacingd, \n    Orientationd, ScaleIntensityRanged, MapLabelValued,\n    RandSpatialCropd, RandFlipd, RandRotate90d, RandRotated, \n    NormalizeIntensityd, ConcatItemsd, ToTensord\n)\nfrom monai.data import Dataset, DataLoader, decollate_batch\nfrom monai.networks.nets import AttentionUnet\nfrom monai.losses import DiceCELoss\nfrom monai.metrics import DiceMetric\nfrom monai.networks.utils import one_hot\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:34:10.467940Z\",\"iopub.execute_input\":\"2026-04-03T07:34:10.468532Z\",\"iopub.status.idle\":\"2026-04-03T07:34:10.473214Z\",\"shell.execute_reply.started\":\"2026-04-03T07:34:10.468510Z\",\"shell.execute_reply\":\"2026-04-03T07:34:10.472138Z\"}}\n# --- 1. Setup Device ---\ndevice = torch.device('cuda' if torch.cuda.is_available() else 'cpu')\nprint(f\"Using device: {device}\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:34:10.474329Z\",\"iopub.execute_input\":\"2026-04-03T07:34:10.474709Z\",\"iopub.status.idle\":\"2026-04-03T07:35:49.132373Z\",\"shell.execute_reply.started\":\"2026-04-03T07:34:10.474682Z\",\"shell.execute_reply\":\"2026-04-03T07:35:49.131715Z\"}}\n# --- 2. Data Preparation ---\ninput_tar = '/kaggle/input/brats-2021-task1/BraTS2021_Training_Data.tar'\noutput_dir = '/kaggle/working/BraTS2021/'\n\nif not os.path.exists(output_dir):\n    os.makedirs(output_dir, exist_ok=True)\n    print(f\"Extracting {input_tar}...\")\n    with tarfile.open(input_tar) as tar:\n        tar.extractall(path=output_dir)\n    print(\"Extraction Complete\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:35:49.134371Z\",\"iopub.execute_input\":\"2026-04-03T07:35:49.134627Z\",\"iopub.status.idle\":\"2026-04-03T07:35:49.156511Z\",\"shell.execute_reply.started\":\"2026-04-03T07:35:49.134609Z\",\"shell.execute_reply\":\"2026-04-03T07:35:49.155844Z\"}}\n# --- 3. Prepare Data List (Splitting Train/Val/Test) ---\npatient_ids = sorted(next(os.walk(output_dir))[1])\ndata_dicts = []\nfor p_id in patient_ids:\n    p_path = os.path.join(output_dir, p_id)\n    # Check if files exist to avoid errors\n    if os.path.exists(os.path.join(p_path, f\"{p_id}_flair.nii.gz\")):\n        data_dicts.append({\n            \"flair\": os.path.join(p_path, f\"{p_id}_flair.nii.gz\"),\n            \"t1\": os.path.join(p_path, f\"{p_id}_t1.nii.gz\"),\n            \"t1ce\": os.path.join(p_path, f\"{p_id}_t1ce.nii.gz\"),\n            \"t2\": os.path.join(p_path, f\"{p_id}_t2.nii.gz\"),\n            \"label\": os.path.join(p_path, f\"{p_id}_seg.nii.gz\"),\n        })\n\n# Splitting: 80% Train, 10% Val, 10% Test\nnum_files = len(data_dicts)\ntrain_files = data_dicts[:int(num_files * 0.8)]\nval_files = data_dicts[int(num_files * 0.8):int(num_files * 0.9)]\ntest_files = data_dicts[int(num_files * 0.9):]\n\nprint(f\"Total: {num_files} | Train: {len(train_files)} | Val: {len(val_files)} | Test: {len(test_files)}\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:35:49.157326Z\",\"iopub.execute_input\":\"2026-04-03T07:35:49.157549Z\",\"iopub.status.idle\":\"2026-04-03T07:35:49.175535Z\",\"shell.execute_reply.started\":\"2026-04-03T07:35:49.157527Z\",\"shell.execute_reply\":\"2026-04-03T07:35:49.174707Z\"}}\n# --- 4. Transforms ---\ntrain_transforms = Compose([\n    LoadImaged(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\", \"label\"]),\n    EnsureChannelFirstd(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\", \"label\"]),\n    Orientationd(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\", \"label\"], axcodes=\"RAS\"),\n    MapLabelValued(keys=\"label\", orig_labels=[1, 2, 4], target_labels=[0, 1, 2]),\n    ConcatItemsd(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\"], name=\"image\"),\n    NormalizeIntensityd(keys=\"image\", nonzero=True, channel_wise=True),\n    RandSpatialCropd(keys=[\"image\", \"label\"], roi_size=(128, 128, 64), random_size=False),\n    RandFlipd(keys=[\"image\", \"label\"], prob=0.5, spatial_axis=[0, 1, 2]),\n    RandRotate90d(keys=[\"image\", \"label\"], prob=0.5, max_k=3),\n    ToTensord(keys=[\"image\", \"label\"]),\n])\n\nval_test_transforms = Compose([\n    LoadImaged(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\", \"label\"]),\n    EnsureChannelFirstd(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\", \"label\"]),\n    Orientationd(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\", \"label\"], axcodes=\"RAS\"),\n    MapLabelValued(keys=\"label\", orig_labels=[1, 2, 4], target_labels=[0, 1, 2]),\n    ConcatItemsd(keys=[\"flair\", \"t1\", \"t1ce\", \"t2\"], name=\"image\"),\n    NormalizeIntensityd(keys=\"image\", nonzero=True, channel_wise=True),\n    RandSpatialCropd(keys=[\"image\", \"label\"], roi_size=(128, 128, 64), random_size=False),\n    ToTensord(keys=[\"image\", \"label\"]),\n])\n\ntrain_ds = Dataset(data=train_files, transform=train_transforms)\nval_ds = Dataset(data=val_files, transform=val_test_transforms)\ntest_ds = Dataset(data=test_files, transform=val_test_transforms)\n\ntrain_loader = DataLoader(train_ds, batch_size=2, shuffle=True, num_workers=4, pin_memory=True)\nval_loader = DataLoader(val_ds, batch_size=1, num_workers=2, pin_memory=True)\ntest_loader = DataLoader(test_ds, batch_size=1, num_workers=2, pin_memory=True)\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:35:49.176883Z\",\"iopub.execute_input\":\"2026-04-03T07:35:49.177378Z\",\"iopub.status.idle\":\"2026-04-03T07:35:49.558103Z\",\"shell.execute_reply.started\":\"2026-04-03T07:35:49.177363Z\",\"shell.execute_reply\":\"2026-04-03T07:35:49.557558Z\"}}\n# --- 5. Model, Loss, Optimizer ---\n# Using FlexibleUNet with EfficientNet-B7 backbone\n# AttentionUnet is natively 3D and supports attention gates\nmodel = AttentionUnet(\n    spatial_dims=3,\n    in_channels=4,\n    out_channels=3,\n    channels=(16, 32, 64, 128, 256),\n    strides=(2, 2, 2, 2),\n).to(device)\n\nloss_function = DiceCELoss(to_onehot_y=True, softmax=True)\noptimizer = torch.optim.Adam(model.parameters(), lr=1e-4)\ndice_metric = DiceMetric(include_background=False, reduction=\"mean\")\nscaler = torch.amp.GradScaler('cuda')\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T07:35:49.558810Z\",\"iopub.execute_input\":\"2026-04-03T07:35:49.559007Z\",\"iopub.status.idle\":\"2026-04-03T09:51:31.403688Z\",\"shell.execute_reply.started\":\"2026-04-03T07:35:49.558982Z\",\"shell.execute_reply\":\"2026-04-03T09:51:31.402727Z\"}}\n# --- 6. Training Loop ---\nepochs = 10\ntrain_losses = []\nval_losses = []\n\nfor epoch in range(epochs):\n    model.train()\n    epoch_train_loss = 0\n    for batch_data in tqdm(train_loader, desc=f\"Epoch {epoch+1}/{epochs} [Train]\"):\n        inputs, labels = batch_data[\"image\"].to(device), batch_data[\"label\"].to(device)\n        optimizer.zero_grad()\n        \n        with torch.amp.autocast('cuda'):\n            outputs = model(inputs)\n            loss = loss_function(outputs, labels)\n        \n        scaler.scale(loss).backward()\n        scaler.step(optimizer)\n        scaler.update()\n        epoch_train_loss += loss.item()\n    \n    avg_train_loss = epoch_train_loss / len(train_loader)\n    train_losses.append(avg_train_loss)\n\n    # Validation\n    model.eval()\n    epoch_val_loss = 0\n    with torch.no_grad():\n        for val_data in tqdm(val_loader, desc=f\"Epoch {epoch+1}/{epochs} [Val]\"):\n            val_inputs, val_labels = val_data[\"image\"].to(device), val_data[\"label\"].to(device)\n            with torch.amp.autocast('cuda'):\n                val_outputs = model(val_inputs)\n                # Validation loss using the same loss function\n                v_loss = loss_function(val_outputs, val_labels)\n            \n            epoch_val_loss += v_loss.item()\n            val_labels_onehot = one_hot(val_labels, num_classes=3)\n            dice_metric(y_pred=val_outputs, y=val_labels_onehot)\n        \n        avg_val_loss = epoch_val_loss / len(val_loader)\n        val_losses.append(avg_val_loss)\n        \n        metric = dice_metric.aggregate().item()\n        dice_metric.reset()\n        print(f\"Epoch {epoch+1}: Train Loss: {avg_train_loss:.4f} | Val Loss: {avg_val_loss:.4f} | Val Dice: {metric:.4f}\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T09:51:31.405264Z\",\"iopub.execute_input\":\"2026-04-03T09:51:31.405640Z\",\"iopub.status.idle\":\"2026-04-03T09:51:31.700380Z\",\"shell.execute_reply.started\":\"2026-04-03T09:51:31.405604Z\",\"shell.execute_reply\":\"2026-04-03T09:51:31.699626Z\"}}\n# --- 7. Plotting Loss Curves ---\nplt.figure(figsize=(8, 6))\nplt.plot(train_losses, label='Training Loss', marker='o')\nplt.plot(val_losses, label='Validation Loss', marker='x')\nplt.title('Attention UNet: Training vs Validation Loss')\nplt.xlabel('Epochs')\nplt.ylabel('Loss')\nplt.legend()\nplt.grid(True)\nplt.show()\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T09:51:31.701248Z\",\"iopub.execute_input\":\"2026-04-03T09:51:31.701545Z\",\"iopub.status.idle\":\"2026-04-03T09:53:44.863452Z\",\"shell.execute_reply.started\":\"2026-04-03T09:51:31.701521Z\",\"shell.execute_reply\":\"2026-04-03T09:53:44.862772Z\"}}\n# --- 8. Final Test Evaluation ---\nprint(\"\\n--- Evaluation on Test Data ---\")\nmodel.eval()\ntest_loss_sum = 0\ndice_metric.reset()\n\nwith torch.no_grad():\n    for test_data in tqdm(test_loader, desc=\"Testing\"):\n        test_inputs, test_labels = test_data[\"image\"].to(device), test_data[\"label\"].to(device)\n        with torch.amp.autocast('cuda'):\n            test_outputs = model(test_inputs)\n            t_loss = loss_function(test_outputs, test_labels)\n        \n        test_loss_sum += t_loss.item()\n        test_labels_onehot = one_hot(test_labels, num_classes=3)\n        dice_metric(y_pred=test_outputs, y=test_labels_onehot)\n\navg_test_loss = test_loss_sum / len(test_loader)\navg_test_dice = dice_metric.aggregate().item()\n\nprint(f\"\\nFinal Test Results:\")\nprint(f\"Average Test Loss: {avg_test_loss:.4f}\")\nprint(f\"Average Test Dice: {avg_test_dice:.4f}\")\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T09:53:44.864397Z\",\"iopub.execute_input\":\"2026-04-03T09:53:44.864672Z\",\"iopub.status.idle\":\"2026-04-03T09:54:08.672094Z\",\"shell.execute_reply.started\":\"2026-04-03T09:53:44.864650Z\",\"shell.execute_reply\":\"2026-04-03T09:54:08.671336Z\"}}\n# --- 9. Visualization ---\ndef visualize_result(data_batch):\n    model.eval()\n    with torch.no_grad():\n        test_input = data_batch[\"image\"][0:1].to(device)\n        test_output = model(test_input)\n        test_output = torch.argmax(test_output, dim=1).detach().cpu()[0]\n    \n    img = data_batch[\"image\"][0, 0] # FLAIR channel\n    lab = data_batch[\"label\"][0, 0]\n    \n    slice_idx = img.shape[-1] // 2\n    plt.figure(figsize=(12, 4))\n    plt.subplot(1, 3, 1); plt.title(\"Input FLAIR\"); plt.imshow(img[:, :, slice_idx], cmap=\"gray\")\n    plt.subplot(1, 3, 2); plt.title(\"Ground Truth\"); plt.imshow(lab[:, :, slice_idx])\n    plt.subplot(1, 3, 3); plt.title(\"Prediction\"); plt.imshow(test_output[:, :, slice_idx])\n    plt.show()\n\n# Visualize one sample from validation\nfor i in range(5):\n    print(f\"Validation Sample #{i+1}\")\n    visualize_result(next(iter(val_loader)))\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T10:34:05.835540Z\",\"iopub.execute_input\":\"2026-04-03T10:34:05.835907Z\",\"iopub.status.idle\":\"2026-04-03T10:34:05.840003Z\",\"shell.execute_reply.started\":\"2026-04-03T10:34:05.835883Z\",\"shell.execute_reply\":\"2026-04-03T10:34:05.839275Z\"}}\nfrom monai.transforms import (\n    Compose,\n    LoadImaged,\n    EnsureChannelFirstd,\n    Orientationd,\n    Resized,\n    ScaleIntensityRanged,\n    ToTensord,\n)\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T10:34:05.841141Z\",\"iopub.execute_input\":\"2026-04-03T10:34:05.841349Z\",\"iopub.status.idle\":\"2026-04-03T10:34:05.858234Z\",\"shell.execute_reply.started\":\"2026-04-03T10:34:05.841334Z\",\"shell.execute_reply\":\"2026-04-03T10:34:05.857608Z\"}}\n# --- 1. Settings ---\nroot_dir = \"/kaggle/working/monai_data\"\nos.makedirs(root_dir, exist_ok=True)\ndevice = torch.device(\"cuda\" if torch.cuda.is_available() else \"cpu\")\n\n# Tasks to import: Task01 (Brain), Task04 (Hippocampus), Task09 (Spleen)\ntasks = [\"Task01_BrainTumour\", \"Task04_Hippocampus\", \"Task09_Spleen\"]\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T10:34:05.859088Z\",\"iopub.execute_input\":\"2026-04-03T10:34:05.859423Z\",\"iopub.status.idle\":\"2026-04-03T10:34:05.875832Z\",\"shell.execute_reply.started\":\"2026-04-03T10:34:05.859400Z\",\"shell.execute_reply\":\"2026-04-03T10:34:05.875248Z\"}}\n# --- 2. Shared Evaluation Transform ---\n# Note: We resize to match your model's expected input (128, 128, 64)\neval_transforms = Compose([\n    LoadImaged(keys=[\"image\", \"label\"]),\n    EnsureChannelFirstd(keys=[\"image\", \"label\"]),\n    Orientationd(keys=[\"image\", \"label\"], axcodes=\"RAS\"),\n    Resized(keys=[\"image\", \"label\"], spatial_size=(128, 128, 64), mode=(\"trilinear\", \"nearest\")),\n    ScaleIntensityRanged(keys=\"image\", a_min=0, a_max=255, b_min=0.0, b_max=1.0, clip=True),\n    ToTensord(keys=[\"image\", \"label\"]),\n])\n\n# %% [code] {\"execution\":{\"iopub.status.busy\":\"2026-04-03T10:34:05.876936Z\",\"iopub.execute_input\":\"2026-04-03T10:34:05.877132Z\",\"iopub.status.idle\":\"2026-04-03T10:39:58.451498Z\",\"shell.execute_reply.started\":\"2026-04-03T10:34:05.877118Z\",\"shell.execute_reply\":\"2026-04-03T10:39:58.450636Z\"}}\nfrom monai.apps import DecathlonDataset\nfrom torch.utils.data import Subset\n\n# --- 3. The Multi-Dataset Test Loop ---\ndice_metric = DiceMetric(include_background=False, reduction=\"mean\")\nmodel.eval()\n\nprint(\"--- Starting Auto-Import Evaluation ---\")\n\nimport shutil\nif os.path.exists(\"/kaggle/working/BraTS2021\"):\n    shutil.rmtree(\"/kaggle/working/BraTS2021\")\n\nfor task_name in tasks:\n    print(f\"\\nProcessing {task_name}...\")\n\n    # Define the specific data directory\n    root_dir = \"/kaggle/working/monai_data\"\n    \n    # Safely clear out ONLY the data folder if it exists\n    if os.path.exists(root_dir):\n        print(f\"Clearing previous data in {root_dir}...\")\n        shutil.rmtree(root_dir)\n    \n    # Recreate the folder for the new task\n    os.makedirs(root_dir, exist_ok=True)\n    \n    # IMPORT DIRECTLY FROM MONAI\n    # download=True handles everything. cache_rate=0.0 keeps RAM safe.\n    full_ds = DecathlonDataset(\n        root_dir=root_dir, \n        task=task_name, \n        section=\"training\", \n        download=True, \n        transform=eval_transforms,\n        cache_rate=0.0 \n    )\n\n    # Sample exactly 20%\n    num_samples = max(1, int(len(full_ds) * 0.2))\n    indices = torch.randperm(len(full_ds))[:num_samples]\n    sampled_ds = Subset(full_ds, indices)\n    \n    test_loader = DataLoader(sampled_ds, batch_size=1, num_workers=2)\n\n    # Evaluation loop\n    with torch.no_grad():\n        for batch_data in tqdm(test_loader, desc=f\"Testing {task_name}\"):\n            inputs = batch_data[\"image\"].to(device)\n            labels = batch_data[\"label\"].to(device)\n\n            # CHANNEL MATCHING HACK:\n            # Your BraTS model expects 4 channels. Most MSD tasks only have 1.\n            # We repeat the single channel 4 times so the model can process it.\n            if inputs.shape[1] == 1:\n                inputs = inputs.repeat(1, 4, 1, 1, 1)\n            elif inputs.shape[1] > 4: # Task01 has 4, but some might have more\n                inputs = inputs[:, :4, ...]\n\n            with torch.cuda.amp.autocast():\n                outputs = model(inputs)\n            \n            # Simple Dice calculation (ignoring multi-class complexities for speed)\n            dice_metric(y_pred=outputs, y=labels)\n\n        final_score = dice_metric.aggregate().item()\n        dice_metric.reset()\n        print(f\">> {task_name} Average Dice: {final_score:.4f}\")","metadata":{"_uuid":"3ace26ee-b8e5-4eac-9b87-3a201af76dc4","_cell_guid":"32debb19-1dc0-4900-a364-2275eb887aa5","trusted":true,"collapsed":false,"jupyter":{"outputs_hidden":false}},"outputs":[],"execution_count":null}]}